#!/usr/bin/env node
/* global console, process */
/**
 * Deploy wrapper for a SolvaPay MCP Cloudflare Worker generated by the
 * `create-solvapay` scaffolder (--type mcp).
 *
 * `wrangler deploy` uploads the `vars` block from `wrangler.jsonc` on
 * every run. That file ships obviously-fake placeholders
 * (`__SOLVAPAY_PRODUCT_REF__`, `__MCP_PUBLIC_BASE_URL__`) so a bare
 * `wrangler deploy` can't connect to someone else's merchant.
 *
 * This script sources `.env` (gitignored) and passes the overridable
 * keys as `--var KEY:VALUE` to `wrangler deploy`. Worker Secrets
 * (`SOLVAPAY_SECRET_KEY`, `UPSTREAM_API_KEY`, the `UPSTREAM_OAUTH_*`
 * family, and `UPSTREAM_API_HEADERS`) are not passed via `--var`. All
 * are uploaded from `.env` automatically on the first deploy when
 * present and not already on the worker (see
 * `ensureSolvaPaySecretKey`, `ensureUpstreamApiKeySecret`,
 * `ensureUpstreamOAuthSecrets`, and `ensureUpstreamApiHeadersSecret`).
 *
 * Single environment by design. Go-live is a key swap, not a separate
 * `--env`: replace `SOLVAPAY_SECRET_KEY` in `.env` with the live key,
 * push the new value with `npx wrangler secret put SOLVAPAY_SECRET_KEY`
 * (the first-deploy auto-upload won't fire because the worker already
 * has a secret), then redeploy.
 *
 * Pass-through: any extra CLI args (e.g. `--dry-run`) are forwarded to
 * `wrangler deploy`. `--yes` / `-y` are consumed by this script (to skip
 * the URL confirm prompt) and stripped before the wrangler call.
 *
 * Pre-flight (before deploy): verifies `wrangler login` and, on accounts
 * that still need it, that a workers.dev subdomain is registered.
 * When `MCP_PUBLIC_BASE_URL` is still the localhost placeholder, resolves
 * the live `*.workers.dev` URL pre-deploy, writes it to `.env`, and
 * verifies wrangler's deploy output matches (defence in depth).
 *
 * URL confirm: prompts the user to confirm the resolved `*.workers.dev`
 * URL before running `wrangler deploy`. Skipped when `wrangler.jsonc`
 * declares a `custom_domain` route, when `--yes` / `-y` is passed, when
 * `SOLVAPAY_DEPLOY_YES=1` is set, when running under `--dry-run`, or
 * when stdin is not a TTY (CI). Declining prints instructions for
 * renaming the workers.dev subdomain or configuring a custom domain.
 */

import { spawnSync } from 'node:child_process'
import { existsSync, readFileSync, writeFileSync } from 'node:fs'
import { homedir } from 'node:os'
import { resolve, dirname, join } from 'node:path'
import * as readline from 'node:readline/promises'
import { fileURLToPath } from 'node:url'

const CF_API_BASE = 'https://api.cloudflare.com/client/v4'
const MCP_PUBLIC_BASE_URL_PLACEHOLDERS = [
  '__MCP_PUBLIC_BASE_URL__',
  'http://localhost:8787',
  'http://127.0.0.1:8787',
]

const here = dirname(fileURLToPath(import.meta.url))
const projectRoot = resolve(here, '..')

const passthrough = process.argv.slice(2)
const dotEnvPath = resolve(projectRoot, '.env')

const OVERRIDABLE_VARS = ['SOLVAPAY_PRODUCT_REF', 'MCP_PUBLIC_BASE_URL', 'SOLVAPAY_API_BASE_URL']

function runWrangler(args, { input, inheritStdio = true, captureOutput = false } = {}) {
  if (captureOutput) {
    return spawnSync('npx', ['wrangler', ...args], {
      cwd: projectRoot,
      input,
      encoding: 'utf8',
      stdio: ['inherit', 'pipe', 'pipe'],
    })
  }

  return spawnSync('npx', ['wrangler', ...args], {
    cwd: projectRoot,
    input,
    encoding: 'utf8',
    stdio: inheritStdio ? (input != null ? ['pipe', 'inherit', 'inherit'] : 'inherit') : 'pipe',
  })
}

function printCapturedWranglerOutput(result) {
  if (result.stdout) process.stdout.write(result.stdout)
  if (result.stderr) process.stderr.write(result.stderr)
}

function listWorkerSecretNames() {
  const result = runWrangler(['secret', 'list', '--format', 'json'], { inheritStdio: false })
  if (result.status !== 0 || !result.stdout?.trim()) return null

  try {
    const parsed = JSON.parse(result.stdout)
    if (!Array.isArray(parsed)) return null
    return parsed
      .map(entry => (typeof entry?.name === 'string' ? entry.name : null))
      .filter(name => name != null)
  } catch {
    return null
  }
}

function putWorkerSecret(name, value) {
  const result = runWrangler(['secret', 'put', name], { input: value })
  if (result.status !== 0) process.exit(result.status ?? 1)
}

function getWranglerWhoami() {
  const result = runWrangler(['whoami', '--json'], { inheritStdio: false })
  if (result.status !== 0 || !result.stdout?.trim()) return null

  try {
    const parsed = JSON.parse(result.stdout)
    return parsed?.loggedIn === true ? parsed : null
  } catch {
    return null
  }
}

function wranglerConfigPaths() {
  const home = homedir()
  const paths = []

  if (process.env.WRANGLER_HOME) {
    paths.push(join(process.env.WRANGLER_HOME, 'config', 'default.toml'))
  }

  paths.push(join(home, 'Library', 'Preferences', '.wrangler', 'config', 'default.toml'))
  paths.push(join(home, '.wrangler', 'config', 'default.toml'))

  return paths
}

function readWranglerOAuthToken() {
  for (const path of wranglerConfigPaths()) {
    if (!existsSync(path)) continue
    const match = readFileSync(path, 'utf8').match(/^oauth_token\s*=\s*"([^"]+)"/m)
    if (match?.[1]) return match[1]
  }
  return null
}

function resolveCloudflareApiToken() {
  const fromEnv = process.env.CLOUDFLARE_API_TOKEN?.trim()
  if (fromEnv) return fromEnv
  return readWranglerOAuthToken()
}

function readWranglerAccountIdFromConfig() {
  return readWranglerConfig().accountId
}

function stripJsoncComments(text) {
  let result = ''
  let i = 0
  let inString = false
  let stringChar = ''
  let escaped = false

  while (i < text.length) {
    const c = text[i]
    const next = text[i + 1]

    if (inString) {
      result += c
      if (escaped) {
        escaped = false
      } else if (c === '\\') {
        escaped = true
      } else if (c === stringChar) {
        inString = false
      }
      i++
      continue
    }

    if (c === '"' || c === "'") {
      inString = true
      stringChar = c
      result += c
      i++
      continue
    }

    if (c === '/' && next === '/') {
      while (i < text.length && text[i] !== '\n') i++
      continue
    }

    if (c === '/' && next === '*') {
      i += 2
      while (i < text.length - 1 && !(text[i] === '*' && text[i + 1] === '/')) i++
      i += 2
      continue
    }

    result += c
    i++
  }

  return result
}

function readWranglerConfig() {
  const configPath = resolve(projectRoot, 'wrangler.jsonc')
  if (!existsSync(configPath)) {
    return { name: null, accountId: null, hasCustomDomainRoute: false }
  }

  const raw = readFileSync(configPath, 'utf8')
  const contents = stripJsoncComments(raw)
  const nameMatch = contents.match(/"name"\s*:\s*"([^"]+)"/)
  const accountMatch = contents.match(/"account_id"\s*:\s*"([^"]+)"/)
  const hasCustomDomainRoute = /"routes"\s*:\s*\[[\s\S]*?"custom_domain"\s*:\s*true/i.test(
    contents,
  )

  return {
    name: nameMatch?.[1] ?? null,
    accountId: accountMatch?.[1] ?? null,
    hasCustomDomainRoute,
  }
}

function resolveCloudflareAccountId(whoami) {
  const fromEnv = process.env.CLOUDFLARE_ACCOUNT_ID?.trim()
  if (fromEnv) return fromEnv

  const fromConfig = readWranglerAccountIdFromConfig()
  if (fromConfig) return fromConfig

  const accounts = whoami?.accounts
  if (!Array.isArray(accounts) || accounts.length === 0) return null

  if (accounts.length > 1) {
    console.warn(
      `Multiple Cloudflare accounts found — using ${accounts[0].name} (${accounts[0].id}). Set CLOUDFLARE_ACCOUNT_ID or wrangler.jsonc account_id to pin another.`,
    )
  }

  return accounts[0].id
}

// Cloudflare canonically signals "workers.dev subdomain not registered" via
// `error.code === 10007` in the response body — see cloudflare/workers-sdk's
// `packages/wrangler/src/routes.ts` `getWorkersDevSubdomain`. The HTTP status
// varies (the API often returns 200 with a `success: false` envelope) and
// the error message text is not guaranteed to mention "subdomain", so we key
// off the numeric code primarily and fall back to status / message heuristics.
const SUBDOMAIN_NOT_FOUND_CODE = 10007

function isSubdomainNotRegisteredResponse(status, body) {
  if (status === 404) return true
  if (!body || typeof body !== 'object') return false

  const errors = Array.isArray(body.errors) ? body.errors : []
  return errors.some(error => {
    if (error?.code === SUBDOMAIN_NOT_FOUND_CODE) return true
    const message = typeof error?.message === 'string' ? error.message : ''
    return /subdomain|workers\.dev|onboarding/i.test(message)
  })
}

async function fetchWorkersSubdomain(accountId, apiToken) {
  const response = await fetch(`${CF_API_BASE}/accounts/${accountId}/workers/subdomain`, {
    headers: { Authorization: `Bearer ${apiToken}` },
  })

  let body = null
  try {
    body = await response.json()
  } catch {
    body = null
  }

  if (isSubdomainNotRegisteredResponse(response.status, body)) {
    return { registered: false }
  }

  if (!response.ok || body?.success === false) {
    const detail =
      body?.errors?.map(error => error.message).filter(Boolean).join('; ') ||
      `HTTP ${response.status}`
    throw new Error(`Cloudflare workers/subdomain check failed: ${detail}`)
  }

  const subdomain = typeof body?.result?.subdomain === 'string' ? body.result.subdomain : ''
  if (!subdomain.trim()) return { registered: false }

  return { registered: true, subdomain }
}

function failNotLoggedIn() {
  console.error(
    [
      '',
      'Not logged in to Cloudflare.',
      '',
      'Run:',
      '  npx wrangler login',
      '',
      'Then re-run `npm run deploy`.',
      '',
    ].join('\n'),
  )
  process.exit(1)
}

function failSubdomainNotRegistered(accountId) {
  console.error(
    [
      '',
      'This Cloudflare account has not registered a workers.dev subdomain yet.',
      'Register one (one-time setup), then re-run `npm run deploy`:',
      '',
      `  https://dash.cloudflare.com/${accountId}/workers/onboarding`,
      '',
    ].join('\n'),
  )
  process.exit(1)
}

/**
 * Hit `GET /v1/sdk/merchant` with the deployer's `SOLVAPAY_SECRET_KEY`
 * to confirm the SolvaPay backend has a merchant record for it before
 * `wrangler deploy` uploads the secret. Without this check, a key
 * without a merchant still authenticates, gets uploaded as a Worker
 * secret, and then every paid tool's bootstrap fails post-deploy with
 * `Provider not found (404)`. Catching it here makes the deploy a no-op
 * instead of a half-success.
 *
 * Behaviour:
 *   - 200          → return (preflight passes).
 *   - 404          → print recovery message + `process.exit(1)`.
 *   - 401          → print `npx solvapay init` hint + `process.exit(1)`.
 *   - other / err  → soft warning; deploy continues. Network errors
 *                    are common in CI runners and shouldn't block deploys.
 *
 * Skips cleanly when `SOLVAPAY_SECRET_KEY` is absent from `.env` (the
 * worker likely already has it as a secret, set out-of-band).
 */
async function runSolvaPayPreflight({ secretKey, apiBaseUrl, dryRun = false } = {}) {
  if (!secretKey) {
    console.warn(
      '⚠  Skipping SolvaPay merchant preflight — SOLVAPAY_SECRET_KEY missing from .env. The worker may still have a secret set out-of-band; redeploy with the key in .env if you want this check to run.',
    )
    return
  }

  const base = (apiBaseUrl ?? 'https://api.solvapay.com').replace(/\/+$/, '')
  const url = `${base}/v1/sdk/merchant`

  if (dryRun) {
    console.log(`[dry-run] would verify SolvaPay merchant at ${url}`)
  }

  let response
  try {
    response = await fetch(url, {
      method: 'GET',
      headers: { Authorization: `Bearer ${secretKey}` },
    })
  } catch (err) {
    console.warn(
      `⚠  SolvaPay merchant preflight failed (network error: ${err?.message ?? err}). Continuing deploy — paid tools may fail at runtime if the secret key is wrong.`,
    )
    return
  }

  if (response.ok) {
    console.log('SolvaPay merchant ok — proceeding with deploy.')
    return
  }

  if (response.status === 404) {
    console.error(
      [
        '',
        '❌ SolvaPay merchant preflight failed: Provider not found (404).',
        '',
        '   The SOLVAPAY_SECRET_KEY in .env authenticates against SolvaPay,',
        '   but no merchant record exists for it. Every paid tool on the',
        '   deployed worker would fail with `Provider not found` post-deploy.',
        '',
        '   To recover:',
        '     1. Run `npx solvapay init` in the project root to create the',
        '        merchant and write a valid key to .env.',
        '     2. Re-run `npm run deploy` once the key in .env is for an',
        '        existing merchant.',
        '',
      ].join('\n'),
    )
    process.exit(1)
  }

  if (response.status === 401) {
    console.error(
      [
        '',
        '❌ SolvaPay merchant preflight failed: Unauthorized (401).',
        '',
        '   The SOLVAPAY_SECRET_KEY in .env was rejected by the SolvaPay API.',
        '   Run `npx solvapay init` to refresh credentials and retry.',
        '',
      ].join('\n'),
    )
    process.exit(1)
  }

  const detail = await response.text().catch(() => '')
  console.warn(
    `⚠  SolvaPay merchant preflight returned ${response.status}. Continuing deploy. Detail: ${detail}`,
  )
}

async function runDeployPreflight({ dryRun = false } = {}) {
  const whoami = getWranglerWhoami()
  if (!whoami) {
    failNotLoggedIn()
  }

  const accountId = resolveCloudflareAccountId(whoami)
  if (!accountId) {
    console.error(
      [
        '',
        'Could not resolve a Cloudflare account id.',
        'Set CLOUDFLARE_ACCOUNT_ID, add account_id to wrangler.jsonc, or run `npx wrangler login`.',
        '',
      ].join('\n'),
    )
    process.exit(1)
  }

  const apiToken = resolveCloudflareApiToken()
  if (!apiToken) {
    console.error(
      [
        '',
        'Could not resolve Cloudflare API credentials for the workers.dev pre-flight.',
        'Run `npx wrangler login`, or set CLOUDFLARE_API_TOKEN (and CLOUDFLARE_ACCOUNT_ID in CI).',
        '',
      ].join('\n'),
    )
    process.exit(1)
  }

  if (dryRun) {
    console.log('[dry-run] verifying workers.dev subdomain registration')
  }

  const subdomain = await fetchWorkersSubdomain(accountId, apiToken)
  if (!subdomain.registered) {
    failSubdomainNotRegistered(accountId)
  }

  if (dryRun) {
    console.log(`[dry-run] workers.dev subdomain ok (${subdomain.subdomain}.workers.dev)`)
  }

  return {
    accountId,
    apiToken,
    workersSubdomain: subdomain.subdomain,
  }
}

function ensureUpstreamApiKeySecret(localEnv, { dryRun = false, force = false } = {}) {
  const value = localEnv.UPSTREAM_API_KEY?.trim()
  if (!value) return

  const existing = listWorkerSecretNames()
  if (existing?.includes('UPSTREAM_API_KEY')) {
    console.log('UPSTREAM_API_KEY already set on worker — skipping upload.')
    return
  }

  if (looksLikePlaceholderUpstreamKey(value) && !force) {
    console.warn(
      [
        '',
        `⚠  UPSTREAM_API_KEY in .env looks like a placeholder ("${value}").`,
        '   Uploading it as a Worker secret will let paid tools call the',
        '   upstream API with an invalid key. Update .env with the real',
        '   value and re-run `npm run deploy`. Pass --force to upload anyway.',
        '',
      ].join('\n'),
    )
    process.exit(1)
  }

  if (dryRun) {
    console.log('[dry-run] would upload UPSTREAM_API_KEY from .env to Worker Secrets')
    return
  }

  console.log('Uploading UPSTREAM_API_KEY from .env to Worker Secrets…')
  putWorkerSecret('UPSTREAM_API_KEY', value)
}

// `UPSTREAM_OAUTH_*` mirrors `UPSTREAM_API_KEY` semantics: scaffold writes
// these when `selections.json.upstreamAuth.kind` is
// `oauth2-client-credentials`. Uploaded once on first deploy, skipped if
// already present on the worker. `scope` and `audience` are optional —
// the deploy script only uploads them when scaffold wrote them.
const OAUTH_REQUIRED_SECRETS = ['UPSTREAM_OAUTH_TOKEN_URL', 'UPSTREAM_OAUTH_CLIENT_ID', 'UPSTREAM_OAUTH_CLIENT_SECRET']
const OAUTH_OPTIONAL_SECRETS = ['UPSTREAM_OAUTH_SCOPE', 'UPSTREAM_OAUTH_AUDIENCE']

function ensureUpstreamOAuthSecrets(localEnv, { dryRun = false } = {}) {
  const present = OAUTH_REQUIRED_SECRETS.filter(name => (localEnv[name] ?? '').trim().length > 0)
  if (present.length === 0) return

  if (present.length < OAUTH_REQUIRED_SECRETS.length) {
    const missing = OAUTH_REQUIRED_SECRETS.filter(name => !(localEnv[name] ?? '').trim())
    console.error(
      [
        '',
        `❌ OAuth upstream auth is partially configured in .env. Missing: ${missing.join(', ')}.`,
        '   Either populate all three required keys or remove the OAuth block from .env.',
        '',
      ].join('\n'),
    )
    process.exit(1)
  }

  const existing = listWorkerSecretNames()
  const allKeys = [...OAUTH_REQUIRED_SECRETS, ...OAUTH_OPTIONAL_SECRETS]
  for (const name of allKeys) {
    const value = (localEnv[name] ?? '').trim()
    if (!value) continue
    if (existing?.includes(name)) {
      console.log(`${name} already set on worker — skipping upload.`)
      continue
    }
    if (dryRun) {
      console.log(`[dry-run] would upload ${name} from .env to Worker Secrets`)
      continue
    }
    console.log(`Uploading ${name} from .env to Worker Secrets…`)
    putWorkerSecret(name, value)
  }
}

// `UPSTREAM_API_HEADERS` mirrors `UPSTREAM_API_KEY` semantics for the
// `apiKey-multi` upstream auth kind: scaffold writes a single compact-JSON
// var holding all static credential headers. Uploaded once on first deploy,
// skipped if already present on the worker.
function ensureUpstreamApiHeadersSecret(localEnv, { dryRun = false } = {}) {
  const value = localEnv.UPSTREAM_API_HEADERS?.trim()
  if (!value) return

  const existing = listWorkerSecretNames()
  if (existing?.includes('UPSTREAM_API_HEADERS')) {
    console.log('UPSTREAM_API_HEADERS already set on worker — skipping upload.')
    return
  }

  if (dryRun) {
    console.log('[dry-run] would upload UPSTREAM_API_HEADERS from .env to Worker Secrets')
    return
  }

  console.log('Uploading UPSTREAM_API_HEADERS from .env to Worker Secrets…')
  putWorkerSecret('UPSTREAM_API_HEADERS', value)
}

// Conservative heuristic: catches the typical scaffold/agent placeholders
// ("api-key-petstore", "your-api-key", "test-key", "todo", etc.) without
// false-positiving on real API keys (which are typically >= 20 chars and
// look like hex / base64 / UUIDs).
function looksLikePlaceholderUpstreamKey(value) {
  if (value.length < 10) return true
  if (/^api[-_]?key[-_]/i.test(value)) return true
  if (/^(your|placeholder|example|sample|test|demo|todo|fake|dummy)[-_]/i.test(value)) return true
  if (/^(your|placeholder|example|sample|test|demo|todo|fake|dummy)-api-key$/i.test(value)) return true
  if (/^changeme/i.test(value)) return true
  return false
}

// Print copy-paste connection snippets for Cursor / Claude Desktop /
// ChatGPT / MCP Inspector pointing at the resolved deployed URL.
// Mirrors the scaffold-time snippet but inlined here because the
// scaffolded project owns deploy.mjs after copy and can't import
// from the SDK package.
function printDeployedConnectionSnippets(publicUrl, workerName) {
  const url = publicUrl.replace(/\/+$/, '')
  const name = workerName || 'solvapay-mcp'
  const out = (line) => process.stdout.write(`${line}\n`)
  out('')
  out('Connect an MCP client to the deployed worker:')
  out('')
  out('  Cursor (~/.cursor/mcp.json):')
  out(`    { "mcpServers": { "${name}": { "url": "${url}/" } } }`)
  out('')
  out('  Claude Desktop (claude_desktop_config.json):')
  out(
    `    { "mcpServers": { "${name}": { "command": "npx", "args": ["mcp-remote", "${url}/"] } } }`,
  )
  out('')
  out(`  ChatGPT Custom MCP Connector URL:  ${url}/`)
  out('')
  out(`  MCP Inspector:  npx @modelcontextprotocol/inspector  (set URL to ${url}/)`)
  out('')
}

// Mirror of ensureUpstreamApiKeySecret for the SolvaPay merchant key.
// Symmetric "first deploy auto-uploads, subsequent deploys skip" pattern.
// Go-live (sandbox→live key swap) does not hit this branch because the
// worker already has a secret; the user pushes the new value with
// `npx wrangler secret put SOLVAPAY_SECRET_KEY` before redeploying.
function ensureSolvaPaySecretKey(localEnv, { dryRun = false } = {}) {
  const value = localEnv.SOLVAPAY_SECRET_KEY?.trim()
  if (!value) return

  const existing = listWorkerSecretNames()
  if (existing?.includes('SOLVAPAY_SECRET_KEY')) {
    console.log('SOLVAPAY_SECRET_KEY already set on worker — skipping upload.')
    return
  }

  if (dryRun) {
    console.log('[dry-run] would upload SOLVAPAY_SECRET_KEY from .env to Worker Secrets')
    return
  }

  console.log('Uploading SOLVAPAY_SECRET_KEY from .env to Worker Secrets…')
  putWorkerSecret('SOLVAPAY_SECRET_KEY', value)
}

function normalizeBaseUrl(value) {
  return value.trim().replace(/\/+$/, '')
}

function isMcpPublicBaseUrlPlaceholder(value) {
  if (!value?.trim()) return true
  const normalized = normalizeBaseUrl(value)
  return MCP_PUBLIC_BASE_URL_PLACEHOLDERS.some(
    placeholder => normalized === normalizeBaseUrl(placeholder),
  )
}

function buildWorkersDevUrl(workerName, accountSubdomain) {
  return `https://${workerName}.${accountSubdomain}.workers.dev`
}

function writeDotEnvValue(key, value) {
  const contents = readFileSync(dotEnvPath, 'utf8')
  const lineRe = new RegExp(`^${key}=.*$`, 'm')
  const newLine = `${key}=${value}`
  const next = lineRe.test(contents)
    ? contents.replace(lineRe, newLine)
    : `${contents.replace(/\n?$/, '\n')}${newLine}\n`
  writeFileSync(dotEnvPath, next, 'utf8')
}

function warnManualMcpPublicBaseUrlStep() {
  console.warn(
    '⚠  MCP_PUBLIC_BASE_URL was not auto-resolved. After deploy, set it to the wrangler-printed URL in .env and re-run `npm run deploy`.',
  )
}

function ensureMcpPublicBaseUrl(localEnv, preflight, { dryRun = false } = {}) {
  const current = localEnv.MCP_PUBLIC_BASE_URL?.trim()
  if (!isMcpPublicBaseUrlPlaceholder(current)) return null

  const { name, hasCustomDomainRoute } = readWranglerConfig()
  if (hasCustomDomainRoute) return null

  if (!name || name.includes('__')) {
    console.warn('⚠  Could not read worker name from wrangler.jsonc — skipping MCP_PUBLIC_BASE_URL auto-resolution.')
    warnManualMcpPublicBaseUrlStep()
    return null
  }

  const workersSubdomain = preflight?.workersSubdomain
  if (!workersSubdomain) {
    warnManualMcpPublicBaseUrlStep()
    return null
  }

  const resolved = buildWorkersDevUrl(name, workersSubdomain)

  if (dryRun) {
    console.log(`[dry-run] would set MCP_PUBLIC_BASE_URL=${resolved} in .env`)
    localEnv.MCP_PUBLIC_BASE_URL = resolved
    return resolved
  }

  if (!existsSync(dotEnvPath)) {
    warnManualMcpPublicBaseUrlStep()
    return null
  }

  writeDotEnvValue('MCP_PUBLIC_BASE_URL', resolved)
  localEnv.MCP_PUBLIC_BASE_URL = resolved
  console.log(`Set MCP_PUBLIC_BASE_URL=${resolved} in .env`)
  return resolved
}

function parseDeployedWorkersDevUrl(output) {
  const matches = output.match(/https:\/\/[^\s/]+\.workers\.dev/g)
  if (!matches?.length) return null
  return normalizeBaseUrl(matches[matches.length - 1])
}

function verifyDeployedWorkersDevUrl(expected, output) {
  const deployed = parseDeployedWorkersDevUrl(output)
  if (!deployed) {
    console.warn(
      `⚠  Could not parse deployed workers.dev URL from wrangler output. Expected: ${expected}`,
    )
    return
  }

  const normalizedExpected = normalizeBaseUrl(expected)
  if (normalizedExpected !== deployed) {
    console.warn(
      `⚠  Deployed URL (${deployed}) does not match MCP_PUBLIC_BASE_URL baked into deploy (${normalizedExpected}). Update .env and redeploy.`,
    )
    return
  }

  console.log(`MCP_PUBLIC_BASE_URL verified: ${deployed}`)
}

async function promptUser(question) {
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout })
  try {
    return await rl.question(question)
  } finally {
    rl.close()
  }
}

function printDeclineInstructions(accountId) {
  const accountFragment = accountId ?? '<accountId>'
  console.error(
    [
      '',
      'Aborted. To pick a different deployment URL:',
      '',
      '  • Rename the account-wide workers.dev subdomain (affects every Worker on the account):',
      `      https://dash.cloudflare.com/${accountFragment}/workers/subdomain`,
      '',
      '  • Or attach a custom domain to this Worker by adding a routes block to wrangler.jsonc:',
      '      "routes": [{ "pattern": "mcp.your-company.com", "custom_domain": true }]',
      '    then set MCP_PUBLIC_BASE_URL in .env to match. See deploy.md step 2.',
      '',
      'Re-run `npm run deploy` (optionally with --yes) once the URL is what you want.',
      '',
    ].join('\n'),
  )
}

async function confirmDeploymentUrl(localEnv, preflight, { dryRun = false, yes = false } = {}) {
  const { hasCustomDomainRoute } = readWranglerConfig()
  if (hasCustomDomainRoute) return 'proceed'

  const current = localEnv.MCP_PUBLIC_BASE_URL?.trim()
  if (!current || isMcpPublicBaseUrlPlaceholder(current)) return 'proceed'
  const candidate = normalizeBaseUrl(current)

  if (dryRun) {
    console.log(`[dry-run] would confirm deploy target: ${candidate}`)
    return 'proceed'
  }

  if (yes || !process.stdin.isTTY) {
    console.log(`Deploy target: ${candidate} (auto-confirmed)`)
    return 'proceed'
  }

  const answer = (await promptUser(`Deploy to ${candidate} ? [Y/n] `)).trim().toLowerCase()
  if (answer === '' || answer === 'y' || answer === 'yes') return 'proceed'

  printDeclineInstructions(preflight?.accountId)
  return 'abort'
}

function parseDotEnv(contents) {
  const env = {}
  for (const rawLine of contents.split(/\r?\n/)) {
    const line = rawLine.trim()
    if (!line || line.startsWith('#')) continue
    const match = line.match(/^([A-Z_][A-Z0-9_]*)\s*=\s*(.*)$/i)
    if (!match) continue
    let [, key, value] = match
    value = value.trim()
    if (
      (value.startsWith('"') && value.endsWith('"')) ||
      (value.startsWith("'") && value.endsWith("'"))
    ) {
      value = value.slice(1, -1)
    } else {
      const commentIdx = value.search(/\s+#/)
      if (commentIdx >= 0) value = value.slice(0, commentIdx).trim()
    }
    env[key] = value
  }
  return env
}

const localEnv = existsSync(dotEnvPath) ? parseDotEnv(readFileSync(dotEnvPath, 'utf8')) : {}

if (!existsSync(dotEnvPath)) {
  console.error(
    [
      '',
      `⚠  ${dotEnvPath} not found — deploying with placeholder vars from wrangler.jsonc.`,
      '   Run `npx solvapay init` (which writes SOLVAPAY_SECRET_KEY) and verify the other',
      '   keys in .env match your merchant, then re-run `npm run deploy` — it uploads',
      '   SOLVAPAY_SECRET_KEY from .env as a Worker secret on the first deploy.',
      '',
    ].join('\n'),
  )
}

const dryRun = passthrough.includes('--dry-run')
const yesFlag =
  passthrough.includes('--yes') ||
  passthrough.includes('-y') ||
  process.env.SOLVAPAY_DEPLOY_YES === '1'
const forceFlag = passthrough.includes('--force')

const preflight = await runDeployPreflight({ dryRun })
const resolvedPublicUrl = ensureMcpPublicBaseUrl(localEnv, preflight, { dryRun })

const confirmation = await confirmDeploymentUrl(localEnv, preflight, { dryRun, yes: yesFlag })
if (confirmation === 'abort') process.exit(1)

// Verify the merchant exists on the SolvaPay backend before uploading
// the secret key. Otherwise a 404-from-the-backend deploy looks like a
// success at the `wrangler deploy` level but every paid tool fails at
// runtime.
await runSolvaPayPreflight({
  secretKey: localEnv.SOLVAPAY_SECRET_KEY?.trim(),
  apiBaseUrl: localEnv.SOLVAPAY_API_BASE_URL?.trim(),
  dryRun,
})

ensureSolvaPaySecretKey(localEnv, { dryRun })
ensureUpstreamApiKeySecret(localEnv, { dryRun, force: forceFlag })
ensureUpstreamOAuthSecrets(localEnv, { dryRun })
ensureUpstreamApiHeadersSecret(localEnv, { dryRun })

const wranglerPassthrough = passthrough.filter(
  arg => arg !== '--yes' && arg !== '-y' && arg !== '--force',
)
const wranglerArgs = ['deploy']
for (const name of OVERRIDABLE_VARS) {
  const value = localEnv[name]
  if (value) wranglerArgs.push('--var', `${name}:${value}`)
}
wranglerArgs.push(...wranglerPassthrough)

const result = runWrangler(wranglerArgs, { captureOutput: true })
printCapturedWranglerOutput(result)

if (resolvedPublicUrl && !dryRun) {
  verifyDeployedWorkersDevUrl(resolvedPublicUrl, `${result.stdout ?? ''}\n${result.stderr ?? ''}`)
}

if (!dryRun && (result.status ?? 1) === 0) {
  const finalUrl = localEnv.MCP_PUBLIC_BASE_URL?.trim()
  if (finalUrl) {
    const { name } = readWranglerConfig()
    printDeployedConnectionSnippets(finalUrl, name)
  }
}

process.exit(result.status ?? 1)
